 22→/// Browser automation tool for interacting with web pages.
 23→///
 24→/// Unlike `web_fetch` which just retrieves page content, this tool allows
 25→/// full browser interaction: clicking buttons, filling forms, taking
 26→/// screenshots, and executing JavaScript.
 27→///
 28→/// This tool automatically tracks and reuses browser session IDs. When
 29→/// the LLM doesn't provide a session_id (or provides empty string), the
 30→/// tool will reuse the most recently created browser session for the current
 31→/// chat session. This prevents pool exhaustion without leaking browser state
 32→/// across unrelated chats.
 33→pub struct BrowserTool {
 34→    config: moltis_browser::BrowserConfig,
 35→    manager: OnceCell<Arc<BrowserManager>>,
 36→    sandbox_router: Option<Arc<SandboxRouter>>,
 37→    /// Track the most recent browser session ID per chat/session context.
 38→    /// This prevents pool exhaustion when the LLM forgets to pass session_id,
 39→    /// without reusing a stale browser across different chats.
 40→    /// Bounded to [`MAX_TRACKED_SESSIONS`] to prevent unbounded growth when
 41→    /// chats end without an explicit browser close action.
 42→    session_ids: RwLock<HashMap<String, String>>,
 43→}
