  1→use std::net::{IpAddr, ToSocketAddrs};
  2→
  3→use {crate::error::Error, url::Url};
  4→
  5→use crate::Result;
  6→
  7→/// Check if an IP is covered by an SSRF allowlist entry.
  8→#[must_use]
  9→pub fn is_ssrf_allowed(ip: &IpAddr, allowlist: &[ipnet::IpNet]) -> bool {
 10→    allowlist.iter().any(|net| net.contains(ip))
 11→}
 12→
 13→/// Check if an IP address is private, loopback, link-local, or otherwise
 14→/// unsuitable for outbound fetches.
 15→#[must_use]
 16→pub fn is_private_ip(ip: &IpAddr) -> bool {
 17→    match ip {
 18→        IpAddr::V4(v4) => {
 19→            v4.is_loopback()
 20→                || v4.is_private()
 21→                || v4.is_link_local()
 22→                || v4.is_broadcast()
 23→                || v4.is_unspecified()
 24→                // 100.64.0.0/10 (CGNAT)
 25→                || (v4.octets()[0] == 100 && (v4.octets()[1] & 0xC0) == 64)
 26→                // 192.0.0.0/24
 27→                || (v4.octets()[0] == 192 && v4.octets()[1] == 0 && v4.octets()[2] == 0)
 28→        },
 29→        IpAddr::V6(v6) => {
 30→            v6.is_loopback()
 31→                || v6.is_unspecified()
 32→                // fc00::/7 (unique local)
 33→                || (v6.segments()[0] & 0xFE00) == 0xFC00
 34→                // fe80::/10 (link-local)
 35→                || (v6.segments()[0] & 0xFFC0) == 0xFE80
 36→        },
 37→    }
 38→}
 39→
 40→fn validate_ssrf_ips(host: &str, ips: &[IpAddr], allowlist: &[ipnet::IpNet]) -> Result<()> {
 41→    if ips.is_empty() {
 42→        return Err(Error::message(format!("DNS resolution failed for {host}")));
 43→    }
 44→
 45→    for ip in ips {
 46→        if is_private_ip(ip) && !is_ssrf_allowed(ip, allowlist) {
 47→            return Err(Error::message(format!(
 48→                "SSRF blocked: {host} resolves to private IP {ip}"
 49→            )));
 50→        }
 51→    }
 52→
 53→    Ok(())
 54→}
 55→
 56→/// SSRF protection for async callers.
 57→///
 58→/// Resolves the URL host and rejects private/loopback/link-local IPs unless
 59→/// explicitly allowlisted.
 60→pub async fn ssrf_check(url: &Url, allowlist: &[ipnet::IpNet]) -> Result<()> {
 61→    let host = url
 62→        .host_str()
 63→        .ok_or_else(|| Error::message("URL has no host"))?;
 64→
 65→    if let Ok(ip) = host.parse::<IpAddr>() {
 66→        return validate_ssrf_ips(host, &[ip], allowlist);
 67→    }
 68→
 69→    let port = url.port_or_known_default().unwrap_or(443);
 70→    let addrs: Vec<IpAddr> = tokio::net::lookup_host(format!("{host}:{port}"))
 71→        .await?
 72→        .map(|socket_addr| socket_addr.ip())
 73→        .collect();
 74→    validate_ssrf_ips(host, &addrs, allowlist)
 75→}
 76→
 77→/// SSRF protection for blocking callers.
 78→pub fn ssrf_check_blocking(url: &Url, allowlist: &[ipnet::IpNet]) -> Result<()> {
 79→    let host = url
 80→        .host_str()
 81→        .ok_or_else(|| Error::message("URL has no host"))?;
 82→
 83→    if let Ok(ip) = host.parse::<IpAddr>() {
 84→        return validate_ssrf_ips(host, &[ip], allowlist);
 85→    }
 86→
 87→    let port = url.port_or_known_default().unwrap_or(443);
 88→    let addrs: Vec<IpAddr> = (host, port)
 89→        .to_socket_addrs()?
 90→        .map(|socket_addr| socket_addr.ip())
 91→        .collect();
 92→    validate_ssrf_ips(host, &addrs, allowlist)
 93→}
