220→    fn lookup_env_value(env_values: &HashMap<String, String>, key: &str) -> Option<String> {
221→        std::env::var(key)
222→            .ok()
223→            .filter(|value| !value.trim().is_empty())
224→            .or_else(|| {
225→                env_values
226→                    .get(key)
227→                    .cloned()
228→                    .filter(|value| !value.trim().is_empty())
229→            })
230→    }
