260→    fn cache_get(&self, key: &str) -> Option<serde_json::Value> {
261→        let cache = self.cache.lock().ok()?;
262→        let entry = cache.get(key)?;
263→        if Instant::now() < entry.expires_at {
264→            Some(entry.value.clone())
265→        } else {
266→            None
267→        }
