287→    async fn search_brave(
288→        &self,
289→        query: &str,
290→        count: u8,
291→        params: &serde_json::Value,
292→        accept_language: Option<&str>,
293→        api_key: &str,
294→    ) -> crate::Result<serde_json::Value> {
295→        if api_key.trim().is_empty() {
296→            return Ok(serde_json::json!({
297→                "error": "Brave Search API key not configured",
298→                "hint": "Set BRAVE_API_KEY environment variable or tools.web.search.api_key in config"
299→            }));
300→        }
301→
302→        let mut url = format!(
303→            "https://api.search.brave.com/res/v1/web/search?q={}&count={count}",
304→            urlencoding::encode(query)
305→        );
306→
307→        if let Some(country) = params.get("country").and_then(|v| v.as_str()) {
308→            url.push_str(&format!("&country={country}"));
309→        }
310→        if let Some(lang) = params.get("search_lang").and_then(|v| v.as_str()) {
311→            url.push_str(&format!("&search_lang={lang}"));
312→        }
313→        if let Some(lang) = params.get("ui_lang").and_then(|v| v.as_str()) {
314→            url.push_str(&format!("&ui_lang={lang}"));
315→        }
316→        if let Some(freshness) = params.get("freshness").and_then(|v| v.as_str()) {
317→            url.push_str(&format!("&freshness={freshness}"));
318→        }
319→
320→        let client = crate::shared_http_client();
321→
322→        let mut req = client
323→            .get(&url)
324→            .timeout(self.timeout)
325→            .header("Accept", "application/json")
326→            .header("X-Subscription-Token", api_key);
327→        if let Some(lang) = accept_language {
328→            req = req.header("Accept-Language", lang);
329→        }
330→        let resp = req.send().await?;
331→
332→        if !resp.status().is_success() {
333→            let status = resp.status();
334→            let body = resp.text().await.unwrap_or_default();
335→            return Err(Error::message(format!(
336→                "Brave Search API returned {status}: {body}"
337→            )));
338→        }
339→
340→        let body_text = resp.text().await.map_err(|error| {
341→            Error::message(format!("failed to read Brave response body: {error}"))
342→        })?;
343→        let body: serde_json::Value = serde_json::from_str(&body_text).map_err(|error| {
344→            let snippet: String = body_text.chars().take(400).collect();
345→            Error::message(format!(
346→                "failed to parse Brave JSON body: {error}; body starts with: {snippet}"
347→            ))
348→        })?;
349→        let results = parse_brave_results(&body);
350→
351→        Ok(serde_json::json!({
352→            "provider": "brave",
353→            "query": query,
354→            "results": results,
355→        }))
356→    }
