412→    /// Check whether DuckDuckGo is temporarily blocked due to a prior CAPTCHA.
413→    fn is_ddg_blocked(&self) -> bool {
414→        self.ddg_blocked_until
415→            .lock()
416→            .ok()
417→            .and_then(|guard| *guard)
418→            .is_some_and(|until| Instant::now() < until)
419→    }
420→
421→    /// Block DuckDuckGo for `duration` after a CAPTCHA response.
422→    fn block_ddg(&self, duration: Duration) {
423→        if let Ok(mut guard) = self.ddg_blocked_until.lock() {
424→            *guard = Some(Instant::now() + duration);
425→        }
426→    }
