428→    /// Fallback: search DuckDuckGo's HTML endpoint when no API key is configured.
429→    async fn search_duckduckgo(&self, query: &str, count: u8) -> crate::Result<serde_json::Value> {
430→        // Fail fast if DDG recently returned a CAPTCHA.
431→        if self.is_ddg_blocked() {
432→            return Err(Error::message(
433→                "Web search unavailable: DuckDuckGo is rate-limited (CAPTCHA) and no search \
434→                 API key is configured. Set BRAVE_API_KEY or PERPLEXITY_API_KEY to enable search.",
435→            ));
436→        }
437→
438→        let client = crate::shared_http_client();
439→
440→        let resp = client
441→            .post("https://html.duckduckgo.com/html/")
442→            .timeout(self.timeout)
443→            .header("Content-Type", "application/x-www-form-urlencoded")
444→            .header("Referer", "https://html.duckduckgo.com/")
445→            .body(format!("q={}&b=", urlencoding::encode(query)))
446→            .send()
447→            .await?;
448→
449→        if !resp.status().is_success() {
450→            let status = resp.status();
451→            return Err(Error::message(format!("DuckDuckGo returned HTTP {status}")));
452→        }
453→
454→        let html = resp.text().await?;
455→
456→        if html.contains("challenge-form") || html.contains("not a Robot") {
457→            // Block DDG for 1 hour so subsequent calls fail instantly.
458→            self.block_ddg(Duration::from_secs(3600));
459→            warn!("DuckDuckGo CAPTCHA detected — blocking fallback for 1 hour");
460→            return Err(Error::message(
461→                "Web search unavailable: DuckDuckGo returned a CAPTCHA challenge. \
462→                 Configure BRAVE_API_KEY or PERPLEXITY_API_KEY for reliable search.",
463→            ));
464→        }
465→
466→        let results = parse_duckduckgo_html(&html, count);
467→
468→        Ok(serde_json::json!({
469→            "provider": "duckduckgo",
470→            "query": query,
471→            "results": results,
472→            "note": "Results from DuckDuckGo (search API key not configured)"
473→        }))
474→    }
475→}
