493→/// Parse Brave JSON response into normalized result rows.
494→fn parse_brave_results(body: &serde_json::Value) -> Vec<BraveResult> {
495→    body.get("web")
496→        .and_then(|web| web.get("results"))
497→        .and_then(serde_json::Value::as_array)
498→        .map(|results| {
499→            results
500→                .iter()
501→                .filter_map(|result| {
502→                    let title = result
503→                        .get("title")
504→                        .and_then(serde_json::Value::as_str)
505→                        .map(str::trim)
506→                        .unwrap_or("");
507→                    let url = result
508→                        .get("url")
509→                        .and_then(serde_json::Value::as_str)
510→                        .map(str::trim)
511→                        .unwrap_or("");
512→                    if title.is_empty() || url.is_empty() {
513→                        return None;
514→                    }
515→                    let description = result
516→                        .get("description")
517→                        .and_then(serde_json::Value::as_str)
518→                        .unwrap_or("")
519→                        .to_string();
520→
521→                    Some(BraveResult {
522→                        title: title.to_string(),
523→                        url: url.to_string(),
524→                        description,
525→                    })
526→                })
527→                .collect()
528→        })
529→        .unwrap_or_default()
530→}
