532→/// Parse DuckDuckGo HTML search results into structured result objects.
533→fn parse_duckduckgo_html(html: &str, max_results: u8) -> Vec<serde_json::Value> {
534→    let mut results = Vec::new();
535→    let max = max_results as usize;
536→    let mut search_from = 0;
537→
538→    while results.len() < max {
539→        let Some(anchor_pos) = html[search_from..].find("class=\"result__a\"") else {
540→            break;
541→        };
542→        let anchor_abs = search_from + anchor_pos;
543→        search_from = anchor_abs + 1;
544→
545→        let Some(href) = extract_href_before(html, anchor_abs) else {
546→            continue;
547→        };
548→
549→        let url = resolve_ddg_redirect(&href);
550→        let title = extract_tag_text(html, anchor_abs);
551→
552→        let snippet = html[anchor_abs..]
553→            .find("class=\"result__snippet\"")
554→            .map(|offset| extract_tag_text(html, anchor_abs + offset))
555→            .unwrap_or_default();
556→
557→        if !url.is_empty() && !title.is_empty() {
558→            results.push(serde_json::json!({
559→                "title": decode_html_entities(&title),
560→                "url": url,
561→                "description": decode_html_entities(&snippet),
562→            }));
563→        }
564→    }
