569→/// Find the `href="..."` attribute value in the tag surrounding `class_pos`.
570→fn extract_href_before(html: &str, class_pos: usize) -> Option<String> {
571→    let tag_start = html[..class_pos].rfind('<')?;
572→    let tag_region = &html[tag_start..];
573→    let href_start = tag_region.find("href=\"")?;
574→    let value_start = href_start + 6;
575→    let value_end = tag_region[value_start..].find('"')?;
576→    Some(tag_region[value_start..value_start + value_end].to_string())
577→}
