617→/// Resolve a DuckDuckGo redirect URL (`//duckduckgo.com/l/?uddg=...`) to the
618→/// actual destination. Returns the href as-is when it's not a redirect.
619→fn resolve_ddg_redirect(href: &str) -> String {
620→    let full_url = if href.starts_with("//") {
621→        format!("https:{href}")
622→    } else {
623→        href.to_string()
624→    };
625→
626→    if full_url.contains("duckduckgo.com/l/")
627→        && let Ok(parsed) = url::Url::parse(&full_url)
628→    {
629→        for (key, value) in parsed.query_pairs() {
630→            if key == "uddg" {
631→                return value.into_owned();
632→            }
633→        }
634→    }
635→
636→    full_url
637→}
