642→        let mut out = String::with_capacity(s.len());
643→        for b in s.bytes() {
644→            match b {
645→                b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
