    #[test]
    fn geolocation_display_with_place() {
        let loc = GeoLocation {
            latitude: 37.759,
            longitude: -122.433,
            place: Some("Noe Valley, San Francisco, CA".to_string()),
            updated_at: None,
        };
        assert_eq!(loc.to_string(), "Noe Valley, San Francisco, CA");
    }

    #[test]
    fn geolocation_display_without_place() {
        let loc = GeoLocation {
            latitude: 37.759,
            longitude: -122.433,
