                && d.category == "invalid-value"
        });
        assert!(
            invalid.is_some(),
            "expected tools.agent_max_iterations invalid-value error, got: {:?}",
            result.diagnostics
        );
    }

    #[test]
    fn mcp_request_timeout_must_be_positive() {
