    fn cache_retention_all_values_parse_correctly() {
        for mode in ["none", "short", "long"] {
            let toml = format!(
                r#"
[providers.anthropic]
cache_retention = "{mode}"
"#
            );
            let result = validate_toml_str(&toml);
            let type_error = result
