        )
        .await
        .unwrap();

        let scrape = result.unwrap();
        assert_eq!(scrape.markdown, "# Hello World\nContent here.");
        assert_eq!(scrape.title.as_deref(), Some("Hello"));
        assert_eq!(scrape.source_url.as_deref(), Some("https://example.com"));
        assert_eq!(scrape.status_code, Some(200));
        mock.assert_async().await;
    }

    #[tokio::test]
    async fn test_firecrawl_scrape_api_error() {
        let mut server = mockito::Server::new_async().await;
        let mock = server
            .mock("POST", "/v1/scrape")
            .with_status(200)
            .with_header("content-type", "application/json")
            .with_body(
                serde_json::json!({
                    "success": false,
                    "error": "Rate limit exceeded"
                })
                .to_string(),
            )
            .create_async()
            .await;

        let result = firecrawl_scrape(
            &reqwest::Client::new(),
            &server.url(),
            "fc-test-key",
            "https://example.com",
            true,
            Duration::from_secs(10),
        )
        .await;

        assert!(result.is_err());
        assert!(result.unwrap_err().to_string().contains("Rate limit"));
        mock.assert_async().await;
    }

    #[tokio::test]
    async fn test_firecrawl_scrape_no_content() {
        let mut server = mockito::Server::new_async().await;
        let mock = server
            .mock("POST", "/v1/scrape")
            .with_status(200)
            .with_header("content-type", "application/json")
            .with_body(
                serde_json::json!({
                    "success": true,
                    "data": {
                        "markdown": "",
                        "metadata": {}
                    }
                })
                .to_string(),
            )
            .create_async()
            .await;

        let result = firecrawl_scrape(
            &reqwest::Client::new(),
            &server.url(),
            "fc-test-key",
            "https://example.com",
            true,
            Duration::from_secs(10),
        )
        .await
        .unwrap();

        assert!(result.is_none());
        mock.assert_async().await;
    }

    #[tokio::test]
    async fn test_firecrawl_scrape_http_error() {
        let mut server = mockito::Server::new_async().await;
        let mock = server
            .mock("POST", "/v1/scrape")
            .with_status(500)
            .with_body("Internal Server Error")
            .create_async()
            .await;

        let result = firecrawl_scrape(
            &reqwest::Client::new(),
            &server.url(),
            "fc-test-key",
            "https://example.com",
            true,
            Duration::from_secs(10),
        )
        .await;

        assert!(result.is_err());
        assert!(result.unwrap_err().to_string().contains("500"));
        mock.assert_async().await;
    }

    #[tokio::test]
    async fn test_firecrawl_search_success() {
        let mut server = mockito::Server::new_async().await;
        let mock = server
            .mock("POST", "/v1/search")
            .with_status(200)
            .with_header("content-type", "application/json")
            .with_body(
                serde_json::json!({
                    "success": true,
                    "data": [
                        {
                            "url": "https://example.com",
                            "title": "Example",
                            "description": "An example site"
                        },
                        {
                            "url": "https://test.com",
                            "title": "Test",
                            "description": "A test site"
                        }
                    ]
                })
                .to_string(),
            )
            .create_async()
            .await;

        let result = firecrawl_search(
            &reqwest::Client::new(),
            &server.url(),
            "fc-test-key",
            "test query",
            5,
            Duration::from_secs(10),
        )
        .await
        .unwrap();

        assert_eq!(result["provider"], "firecrawl");
        assert_eq!(result["query"], "test query");
        let results = result["results"].as_array().unwrap();
        assert_eq!(results.len(), 2);
        assert_eq!(results[0]["url"], "https://example.com");
        mock.assert_async().await;
    }

    #[tokio::test]
    async fn test_firecrawl_search_api_error() {
        let mut server = mockito::Server::new_async().await;
        let mock = server
            .mock("POST", "/v1/search")
            .with_status(403)
            .with_body("Forbidden")
            .create_async()
            .await;

        let result = firecrawl_search(
            &reqwest::Client::new(),
            &server.url(),
            "fc-bad-key",
            "test query",
            5,
            Duration::from_secs(10),
        )
        .await;

        assert!(result.is_err());
        assert!(result.unwrap_err().to_string().contains("403"));
        mock.assert_async().await;
    }

    #[test]
    fn test_resolve_api_key_from_config() {
        let config = test_config(true, Some("fc-from-config"));
        let key = resolve_api_key(&config).unwrap();
        assert_eq!(key.expose_secret(), "fc-from-config");
    }

    #[test]
    fn test_resolve_api_key_none_when_empty() {
        let config = test_config(true, None);
        // Only passes when FIRECRAWL_API_KEY is not set in env.
        if std::env::var("FIRECRAWL_API_KEY").is_err() {
            assert!(resolve_api_key(&config).is_none());
        }
    }
}

