    fn test_html_to_text_mixed_encoding_content() {
        let html =
            "<div>Price: &lt;¥500&gt;</div><script>var x='テスト';</script><p>End \u{FFFD}</p>";
        let text = html_to_text(html);
        assert!(text.contains("Price:"));
        assert!(text.contains("<¥500>"));
