    fn test_with_proxy() {
        let tool = default_tool();
        assert!(tool.proxy_url.is_none());
        let tool = tool.with_proxy("http://127.0.0.1:18791".into());
        assert_eq!(tool.proxy_url.as_deref(), Some("http://127.0.0.1:18791"));
