        assert!(result.unwrap_err().to_string().contains("url"));
    }

    // --- SSRF tests ---

    use rstest::rstest;

    #[rstest]
    #[case("127.0.0.1", true)]
    #[case("192.168.1.1", true)]
    #[case("10.0.0.1", true)]
    #[case("172.16.0.1", true)]
    #[case("169.254.1.1", true)]
    #[case("0.0.0.0", true)]
    #[case("8.8.8.8", false)]
    #[case("1.1.1.1", false)]
    fn test_is_private_ip_v4(#[case] addr: &str, #[case] expected: bool) {
